void jacobi_step(float* f, 
                 const float* f_old, 
                 float* error,
                 int grid_x, int grid_y,
                 int block_x, int block_y) {

  #pragma omp target parallel num_teams(grid_x * grid_y) thread_limit(block_x * block_y)
  {
    int team_id = omp_get_team_num(omp_get_level());
    int bx = team_id % grid_x;
    int by = team_id / grid_x;

    int tx = omp_get_thread_num() % block_x;
    int ty = omp_get_thread_num() / block_x;

    int i = bx * block_x + tx;
    int j = by * block_y + ty;

    static float f_old_tile[18][18];

    f_old_tile[ty+1][tx+1] = f_old[IDX(i,j)];

    if (tx == 0 && i >= 1) {
      f_old_tile[ty+1][tx+0] = f_old[IDX(i-1,j)];
    }
    if (tx == 15 && i <= N-2) {
      f_old_tile[ty+1][tx+2] = f_old[IDX(i+1,j)];
    }
    if (ty == 0 && j >= 1) {
      f_old_tile[ty+0][tx+1] = f_old[IDX(i,j-1)];
    }
    if (ty == 15 && j <= N-2) {
      f_old_tile[ty+2][tx+1] = f_old[IDX(i,j+1)];
    }

    #pragma omp target barrier

    float err = 0.0f;

    if (j >= 1 && j <= N-2) {
      if (i >= 1 && i <= N-2) {

        float new_val = 0.25f * (f_old_tile[ty+1][tx+2] + 
                                 f_old_tile[ty+1][tx+0] + 
                                 f_old_tile[ty+2][tx+1] + 
                                 f_old_tile[ty+0][tx+1]);
        f[IDX(i,j)] = new_val;
        float df = new_val - f_old_tile[ty+1][tx+1];
        err = df * df;
      }
    }

    // Simulate warp reduction logic using OpenMP constructs
    // Since OpenMP target doesn't have direct shuffle, we use a local array and reduction
    static float reduction_array[16];

    // First stage: reduce within x-dimension (simulating warp shuffle in x)
    // We assume block_x is 16. We can just sum up errors in the team.
    // To mimic the specific structure of the CUDA code which does two-stage reduction:
    // 1. Shuffle within warp (x-direction primarily)
    // 2. Store to shared, then shuffle within y-direction

    // Simplified approach for OpenMP: Just sum all errors in the team safely or via reduction
    // However, to preserve algorithmic intent as much as possible without shuffle:
    // We will perform a manual reduction over the threads in the team.

