#include <omp.h>

#define N 2048

#define IDX(i, j) ((i) + (j) * N)

void initialize_data(float* f) {
  #pragma omp target data use_device(f)
  {
    #pragma omp target teams distribute parallel for collapse(2)
    for (int j = 0; j < N; ++j) {
      for (int i = 0; i < N; ++i) {
        if (i == 0 || i == N-1) {
          f[IDX(i,j)] = sinf(j * 2 * M_PI / (N - 1));
        }
        else if (j == 0 || j == N-1) {
          f[IDX(i,j)] = sinf(i * 2 * M_PI / (N - 1));
        }
        else {
          f[IDX(i,j)] = 0.0f;
        }
      }
    }
  }
}

void jacobi_step(float* f, const float* f_old, float* error) {
  #pragma omp target data use_device(f, f_old, error)
  {
    #pragma omp target teams distribute parallel for collapse(2) reduction(+:error[0])
    for (int j = 1; j < N-1; ++j) {
      for (int i = 1; i < N-1; ++i) {
        float val = 0.25f * (f_old[IDX(i+1,j)] + 
                             f_old[IDX(i-1,j)] + 
                             f_old[IDX(i,j+1)] + 
                             f_old[IDX(i,j-1]));
        f[IDX(i,j)] = val;
        float df = val - f_old[IDX(i,j)];
        error[0] += df * df;
      }
    }
  }
}

int main() {
  auto start_time = std::chrono::steady_clock::now();

  float* d_f;
  float* d_f_old;
  float* d_error;

  float* f = (float*) aligned_alloc(64, N * N * sizeof(float));
  float* f_old = (float*) aligned_alloc(64, N * N * sizeof(float));

  initialize_data(f);
  initialize_data(f_old);

  #pragma omp target data copyin(f[0:N*N], f_old[0:N*N]) copyout(d_f[0:N*N], d_f_old[0:N*N])
  {
    d_f = f;
    d_f_old = f_old;
  }

  d_error = (float*) omp_target_alloc(sizeof(float), omp_get_default_device());

  float error = std::numeric_limits<float>::max();
  const float tolerance = 1.e-5f;

  const int max_iters = 10000;
  int num_iters = 0;

  auto start = std::chrono::steady_clock::now();

  while (error > tolerance && num_iters < max_iters) {
    #pragma omp target data use_device(d_error)
    {
      #pragma omp target teams distribute parallel for
      for (int i = 0; i < 1; ++i) {
        d_error[0] = 0.0f;
      }
    }

    jacobi_step(d_f, d_f_old, d_error);

    std::swap(d_f, d_f_old);

    #pragma omp target data use_device(d_error)
    {
      #pragma omp target update host(d_error[0])
    }
    error = d_error[0];

    error = sqrtf(error / (N * N));

    if (num_iters % 1000 == 0) {
      std::cout << "Error after iteration " << num_iters << " = " << error << std::endl;
    }

    ++num_iters;
  }

  auto end = std::chrono::steady_clock::now();
  auto time = std::chrono::duration_cast<std::chrono::nanoseconds>(end - start).count();
  std::cout << "Average execution time per iteration: " << (time * 1e-9f) / num_iters << " (s)\n";

  if (error <= tolerance && num_iters < max_iters) {
    std::cout << "PASS" << std::endl;
  }
  else {
    std::cout << "FAIL" << std::endl;
    return -1;
  }

  omp_target_free(d_error, omp_get_default_device());

  auto end_time = std::chrono::steady_clock::now();
  auto total_time = std::chrono::duration_cast<std::chrono::nanoseconds>(end_time - start_time).count();
  double duration = total_time * 1e-9;
  std::cout << "Total elapsed time: " << std::setprecision(4) << duration << " seconds" << std::endl;

  free(f);
  free(f_old);

  return 0;
}

#include <math.h>
#include <stdio.h>
#include <stdlib.h>
#include <chrono>
#include <omp.h>

#define _QUEENS_BLOCK_SIZE_   128
#define _EMPTY_      -1

typedef struct queen_root{
  unsigned int control;
  int8_t board[12];
} QueenRoot;

inline void prefixesHandleSol(QueenRoot *root_prefixes, unsigned int flag,
                              const char *board, int initialDepth, int num_sol)
{
  root_prefixes[num_sol].control = flag;
  for(int i = 0; i<initialDepth;++i)
    root_prefixes[num_sol].board[i] = board[i];
}

inline bool MCstillLegal(const char *board, const int r)
{

  for (int i = 0; i < r; ++i)
    if (board[i] == board[r]) return false;

  int ld = board[r];  
  int rd = board[r];  
  for (int i = r-1; i >= 0; --i) {
    --ld; ++rd;
    if (board[i] == ld || board[i] == rd) return false;
  }
  return true;
}

bool queens_stillLegal(const char *board, const int r)
{
  bool safe = true;

  for (int i = 0; i < r; ++i)
    if (board[i] == board[r]) safe = false;

  int ld = board[r];  
  int rd = board[r];  
  for (int i = r-1; i >= 0; --i) {
    --ld; ++rd;
    if (board[i] == ld || board[i] == rd) safe = false;
  }
  return safe;
}

void BP_queens_root_dfs(
  int N, unsigned int nPreFixos, int depthPreFixos,
  const QueenRoot *__restrict__ root_prefixes,
  unsigned long long *__restrict__ vector_of_tree_size,
  unsigned long long *__restrict__ sols)
{
  int idx = omp_get_thread_num();
  if (idx < nPreFixos) {
     unsigned int flag = 0;
     unsigned int bit_test = 0;
     char vertice[20];
     int N_l = N;
     int i, depth; 
     unsigned long long  qtd_solutions_thread = 0ULL;
     int depthGlobal = depthPreFixos;
     unsigned long long tree_size = 0ULL;

    for (i = 0; i < N_l; ++i) {
      vertice[i] = _EMPTY_;
    }

    flag = root_prefixes[idx].control;

    for (i = 0; i < depthGlobal; ++i)
      vertice[i] = root_prefixes[idx].board[i];

    depth = depthGlobal;

    do {
      vertice[depth]++;
      bit_test = 0;
      bit_test |= (1<<vertice[depth]);
      if(vertice[depth] == N_l){
        vertice[depth] = _EMPTY_;
      } else if (!(flag & bit_test ) && queens_stillLegal(vertice, depth)){
        ++tree_size;
        flag |= (1ULL<<vertice[depth]);
        depth++;
        if (depth == N_l) { 
          ++qtd_solutions_thread; 
        } else continue;
      } else continue;
      depth--;
      flag &= ~(1ULL<<vertice[depth]);
    } while(depth >= depthGlobal);

    sols[idx] = qtd_solutions_thread;
    vector_of_tree_size[idx] = tree_size;
  }
}

unsigned long long BP_queens_prefixes(int size, int initialDepth, 
                                      unsigned long long *tree_size,
                                      QueenRoot *root_prefixes)
{
  unsigned int flag = 0;
  int bit_test = 0;
  char vertice[20];
  int i, nivel;
  unsigned long long local_tree = 0ULL;
  unsigned long long num_sol = 0;

  for (i = 0; i < size; ++i) {
    vertice[i] = -1;
  }

  nivel = 0;

  do{

    vertice[nivel]++;
    bit_test = 0;
    bit_test |= (1<<vertice[nivel]);

    if(vertice[nivel] == size){
      vertice[nivel] = _EMPTY_;
    }else if ( MCstillLegal(vertice, nivel) && !(flag &  bit_test ) ){ 

      flag |= (1ULL<<vertice[nivel]);
      nivel++;
      ++local_tree;
      if (nivel == initialDepth){ 
        prefixesHandleSol(root_prefixes,flag,vertice,initialDepth,num_sol);
        num_sol++;
      }else continue;
    }else continue;

    nivel--;
    flag &= ~(1ULL<<vertice[nivel]);

  }while(nivel >= 0);

  *tree_size = local_tree;

  return num_sol;
}


void nqueens(short size, int initial_depth, unsigned int n_explorers, QueenRoot *root_prefixes_h ,
             unsigned long long *vector_of_tree_size_h, unsigned long long *sols_h, const int repeat)
{
  unsigned long long *vector_of_tree_size_d;
  unsigned long long *sols_d;
  QueenRoot *root_prefixes_d;

  int num_blocks = ceil((double)n_explorers/_QUEENS_BLOCK_SIZE_);
  int block_size = _QUEENS_BLOCK_SIZE_;

  vector_of_tree_size_d = (unsigned long long*)malloc(n_explorers*sizeof(unsigned long long));
  sols_d = (unsigned long long*)malloc(n_explorers*sizeof(unsigned long long));
  root_prefixes_d = (QueenRoot*)malloc(n_explorers*sizeof(QueenRoot));

  memcpy(root_prefixes_d, root_prefixes_h, n_explorers * sizeof(QueenRoot));

  printf("\n### Regular BP-DFS search. ###\n");

  auto start = std::chrono::steady_clock::now();

  for (int i = 0; i < repeat; i++) {
    #pragma omp target parallel for num_threads(n_explorers)
    {
      BP_queens_root_dfs(
        size,
        n_explorers,
        initial_depth,
        root_prefixes_d,
        vector_of_tree_size_d,
        sols_d);
    }
  }

  auto end = std::chrono::steady_clock::now();
  auto time = std::chrono::duration_cast<std::chrono::nanoseconds>(end - start).count();
  printf("Average kernel execution time: %f (s)\n", (time * 1e-9f) / repeat);

  memcpy(vector_of_tree_size_h, vector_of_tree_size_d, n_explorers*sizeof(unsigned long long));
  memcpy(sols_h, sols_d, n_explorers*sizeof(unsigned long long));

  free(vector_of_tree_size_d);
  free(sols_d);
  free(root_prefixes_d);
}


