#include <assert.h>
#include <stdio.h>
#include <stdlib.h>
#include <math.h>
#include <chrono>
#include <omp.h>

#define MAX_MASK_WIDTH 10
#define MAX_BLOCK_SIZE 1024

template<typename T>
T mask[MAX_MASK_WIDTH];

template<typename T>
void conv1d(const T *in,
            T *out,
            const int input_width,
            const int mask_width,
            const int block_size,
            const int num_blocks)
{
  #pragma omp target parallel for device_type(gpu)
  for (int block_idx = 0; block_idx < num_blocks; block_idx++) {
    int start_idx = block_idx * block_size;
    int end_idx = start_idx + block_size;
    if (end_idx > input_width) end_idx = input_width;

    for (int i = start_idx; i < end_idx; i++) {
      T s = 0;
      int start = i - mask_width / 2;
      for (int j = 0; j < mask_width; j++) {
        if (start + j >= 0 && start + j < input_width) {
          s += in[start + j] * mask<T>[j];
        }
      }
      out[i] = s;
    }
  }
}

template<typename T>
void conv1d_tiled(const T *in,
                  T *out,
                  const int input_width,
                  const int mask_width,
                  const int block_size,
                  const int num_blocks)
{
  int n = mask_width / 2;
  size_t tile_size = block_size + 2 * n;

  #pragma omp target parallel for device_type(gpu)
  for (int block_idx = 0; block_idx < num_blocks; block_idx++) {
    // Simulate shared memory with local array (compiler handles mapping to GPU shared mem if possible, or uses local)
    // Note: OpenMP target offload doesn't have explicit __shared__ like CUDA, but compilers may optimize.
    // We use a local array which acts as the tile for this block.
    T tile(tile_size);

    int base_idx = block_idx * block_size;

    // Load halo left
    for (int t = 0; t < n; t++) {
      int idx = base_idx - n + t;
      if (idx < 0) tile[t] = 0;
      else if (idx >= input_width) tile[t] = 0;
      else tile[t] = in[idx];
    }

    // Load main block
    for (int t = 0; t < block_size; t++) {
      int idx = base_idx + t;
      if (idx >= input_width) tile[n + t] = 0;
      else tile[n + t] = in[idx];
    }

    // Load halo right
    for (int t = 0; t < n; t++) {
      int idx = base_idx + block_size + t;
      if (idx >= input_width) tile[block_size + n + t] = 0;
      else tile[block_size + n + t] = in[idx];
    }

    // Compute
    for (int t = 0; t < block_size; t++) {
      int i = base_idx + t;
      if (i >= input_width) continue;

      T s = 0;
      for (int j = 0; j < mask_width; j++) {
        s += tile[n + t - n + j] * mask<T>[j]; // tile index: t + j
      }
      out[i] = s;
    }
  }
}

template<typename T>
void conv1d_tiled_caching(const T *in,
                          T *out,
                          const int input_width,
                          const int mask_width,
                          const int block_size,
                          const int num_blocks)
{
  int n = mask_width / 2;

  #pragma omp target parallel for device_type(gpu)
  for (int block_idx = 0; block_idx < num_blocks; block_idx++) {
    T tile[block_size];
    int base_idx = block_idx * block_size;
    int next_base_idx = (block_idx + 1) * block_size;

    // Load tile
    for (int t = 0; t < block_size; t++) {
      int idx = base_idx + t;
      if (idx >= input_width) tile[t] = 0;
      else tile[t] = in[idx];
    }

    // Compute
    for (int t = 0; t < block_size; t++) {
      int i = base_idx + t;
      if (i >= input_width) continue;

      int start = i - n;
      T s = 0;
      for (int j = 0; j < mask_width; j++) {
        int in_index = start + j;
        if (in_index >= 0 && in_index < input_width) {
          if (in_index >= base_idx && in_index < next_base_idx) {
            s += tile[in_index - base_idx] * mask<T>[j];
          } else {
            s += in[in_index] * mask<T>[j];
          }
        }
      }
      out[i] = s;
    }
  }
}

template <typename T>
void reference(const T *h_in,
               const T *d_out,
               const T *h_mask,
               const int input_width,
               const int mask_width)
{
  bool ok = true;
  for (int i = 0; i < input_width; i++) {
    T s = 0;
    int start = i - mask_width / 2;
    for (int j = 0; j < mask_width; j++) {
      if (start + j >= 0 && start + j < input_width) {
        s += h_in[start + j] * h_mask[j];
      }
    }
    if (fabs(s - d_out[i]) > 1e-3) {
      ok = false;
      break;
    }
  }
  printf("%s\n", ok ? "PASS" : "FAIL");
}

template <typename T>
void conv1D(const int input_width, const int mask_width, const int repeat)
{
  size_t size_bytes = input_width * sizeof(T);

  T *a, *b;
  a = (T *)malloc(size_bytes); 
  b = (T *)malloc(size_bytes); 

  T h_mask[MAX_MASK_WIDTH];
  for (int i = 0; i < MAX_MASK_WIDTH; i++) h_mask[i] = 1; 

  srand(123);
  for (int i = 0; i < input_width; i++) {
    a[i] = rand() % 256;
  }

  T *d_a, *d_b;

  // Allocate on device using OpenMP target
  #pragma omp target data map(alloc: d_a[0:input_width], d_b[0:input_width])
  {
    // Copy input to device
    #pragma omp target update map(to: d_a[0:input_width])

    // Copy mask to global template variable
    for (int i = 0; i < mask_width; i++) {
      mask<T>[i] = h_mask[i];
    }
    // Ensure mask is updated on device if needed (implicitly handled by template usage in kernels)

    // Warm up / synchronize
    #pragma omp target

    // Run tests
    for (int bs = 64; bs <= MAX_BLOCK_SIZE; bs = bs * 2) {
      int num_blocks = (input_width + bs - 1) / bs;

      auto start = std::chrono::steady_clock::now();
      for (int i = 0; i < repeat; i++) {
        conv1d<T>(d_a, d_b, input_width, mask_width, bs, num_blocks);
      }
      auto end = std::chrono::steady_clock::now();
      auto time = std::chrono::duration_cast<std::chrono::nanoseconds>(end - start).count();
      printf("Average kernel execution time of conv1d kernel (block size %d): %f (us)\n",
             bs, (time * 1e-3f) / repeat);

      #pragma omp target update map(from: d_b[0:input_width])
      reference(a, b, h_mask, input_width, mask_width);
    }

    for (int bs = 64; bs <= MAX_BLOCK_SIZE; bs = bs * 2) {
      int num_blocks = (input_width + bs - 1) / bs;

      auto start = std::chrono::steady_clock::now();
      for (int i = 0; i < repeat; i++) {
        conv1d_tiled<T>(d_a, d_b, input_width, mask_width, bs, num_blocks);
      }
      auto end = std::chrono::steady_clock::now();
      auto time = std::chrono::duration_cast<std::chrono::nanoseconds>(end - start).count();
      printf("Average kernel execution time of conv1d-tiled kernel (block size %d): %f (us)\n",
             bs, (time * 1e-3f) / repeat);

      #pragma omp target update map(from: d_b[0:input_width])
      reference(a, b, h_mask, input_width, mask_width);
    }

    for (int bs = 64; bs <= MAX_BLOCK_SIZE; bs = bs * 2) {
      int num_blocks = (input_width + bs - 1) / bs;

      auto start = std::chrono::steady_clock::now();
      for (int i = 0; i < repeat; i++) {
        conv1d_tiled_caching<T>(d_a, d_b, input_width, mask_width, bs, num_blocks);
      }
      auto end = std::chrono::steady_clock::now();
      auto time = std::chrono::duration_cast<std::chrono::nanoseconds>(end - start).count();
      printf("Average kernel execution time of conv1d-tiled-caching kernel (block size %d): %f (us)\n",
             bs, (time * 1e-3f) / repeat);

      #pragma omp target update map(from: d_b[0:input_width])
      reference(a, b, h_mask, input_width, mask_width);
    }
  }

  free(a);
  free(b);
}

int main(int argc, char* argv[]) {
