  init_array(page_ranks, n, 1.0f / (float) n);

  float *diffs;
  diffs = (float*) malloc(rank_size);

  int *d_pages;
  float *d_maps;
  float *d_page_ranks;
  float *d_diffs;
  unsigned int *d_noutlinks;

  d_pages = (int*)omp_target_alloc(page_size, omp_get_default_device());
  d_page_ranks = (float*)omp_target_alloc(rank_size, omp_get_default_device());
  d_maps = (float*)omp_target_alloc(map_size, omp_get_default_device());
  d_noutlinks = (unsigned int*)omp_target_alloc(link_size, omp_get_default_device());
  d_diffs = (float*)omp_target_alloc(rank_size, omp_get_default_device());

  memset(d_diffs, 0, rank_size);

  omp_target_memcpy(d_pages, pages, page_size, 0, 0, omp_get_default_device(), omp_get_initial_device());
  omp_target_memcpy(d_page_ranks, page_ranks, rank_size, 0, 0, omp_get_default_device(), omp_get_initial_device());
  omp_target_memcpy(d_noutlinks, noutlinks, link_size, 0, 0, omp_get_default_device(), omp_get_initial_device());

  double ktime = 0.0;
  printf("Threshold: %f\n", thresh);

  for (t=1; t<=iter && max_diff>=thresh; ++t) {
    auto start = std::chrono::high_resolution_clock::now();

    map_offload(d_pages, d_page_ranks, d_maps, d_noutlinks, n);
    reduce_offload(d_page_ranks, d_maps, n, d_diffs);

    auto end = std::chrono::high_resolution_clock::now();
    ktime += std::chrono::duration_cast<std::chrono::duration<double>>(end - start).count();

    omp_target_memcpy(diffs, d_diffs, rank_size, 0, 0, omp_get_initial_device(), omp_get_default_device());
    max_diff = maximum_dif(diffs, n);
  }



  omp_target_free(d_pages, omp_get_default_device());
  omp_target_free(d_maps, omp_get_default_device());
  omp_target_free(d_page_ranks, omp_get_default_device());
  omp_target_free(d_noutlinks, omp_get_default_device());
  omp_target_free(d_diffs, omp_get_default_device());

  fprintf(stderr, "Max difference %f is reached at iteration %d\n", max_diff, t);
  printf("\"Options\": \"-n %d -i %d -t %f\". Total kernel execution time: %lf (s)\n",
         n, iter, thresh, ktime);

  memset(diffs, 0, rank_size);
  for (t=1; t<=iter && max_diff_ref>=thresh; ++t) {
    map_ref(pages, page_ranks, maps, noutlinks, n);
    reduce_ref(page_ranks, maps, n, diffs);
    max_diff_ref = maximum_dif(diffs, n);
  }
  bool ok = fabsf(max_diff - max_diff_ref) < 1e-3f;
  printf("%s\n", ok ? "PASS" : "FAIL");

  free(pages);
  free(maps);
  free(page_ranks);
  free(noutlinks);
  free(diffs);

  return 0;
}

#include <stdio.h>
#include <stdlib.h>
#include <string.h>
#include <time.h>
#include <math.h>
#include <getopt.h>
#include <chrono>
#include <omp.h>
#include "reference.h"

#define D_FACTOR (0.85f)
#ifndef BLOCK_SIZE
#define BLOCK_SIZE 256
#endif


const int max_iter = 1000;
const float threshold= 1e-16f;

void map(const int *__restrict__ pages,
         const float *__restrict__ page_ranks,
               float *__restrict__ maps,
         const unsigned int *__restrict__ noutlinks,
         const int n)
{
  #pragma omp target parallel for
  for (int i = 0; i < n; i++) {
    float outbound_rank = page_ranks[i]/(float)noutlinks[i];
    for(int j=0; j<n; ++j){
      maps[(size_t)i*n+j] = pages[(size_t)i*n+j]*outbound_rank;
    }
  }
}

void reduce(      float *__restrict__ page_ranks,
            const float *__restrict__ maps,
            const int n,
                  float *__restrict__ dif)
{

  #pragma omp target parallel for
  for (int j = 0; j < n; j++) {
    float old_rank = page_ranks[j];
    float new_rank = 0.0f;
    for(int i=0; i< n; ++i){
      new_rank += maps[(size_t)i*n + j];
    }

    new_rank = ((1.f-D_FACTOR)/n)+(D_FACTOR*new_rank);
    dif[j] = fmaxf(fabsf(new_rank - old_rank), dif[j]);
    page_ranks[j] = new_rank;
  }
}


int *random_pages(int n, unsigned int *noutlinks, int divisor){
  int i, j, k;
  int *pages = (int*) malloc((size_t)n * n * sizeof(int)); 

  if (divisor <= 0) {
    fprintf(stderr, "ERROR: Invalid divisor '%d' for random initialization, divisor should be greater or equal to 1\n", divisor);
    exit(1);
  }

  for(i=0; i<n; ++i){
    noutlinks[i] = 0;
    for(j=0; j<n; ++j){
      if(i!=j && (abs(rand())%divisor == 0)){
        pages[(size_t)i*n+j] = 1;
        noutlinks[i] += 1;
      }
    }


    if(noutlinks[i] == 0){
      do { k = abs(rand()) % n; } while ( k == i);
      pages[(size_t)i*n + k] = 1;
      noutlinks[i] = 1;
    }
  }
  return pages;
}

void init_array(float *a, int n, float val){
  int i;
  for(i=0; i<n; ++i){
    a[i] = val;
  }
}

void usage(char *argv[]){
  fprintf(stderr, "Usage: %s [-n number of pages] [-i max iterations]"
                  " [-t threshold] [-q divisor for zero density]\n", argv[0]);
}

static struct option size_opts[] =
{

  {"number of pages", 1, NULL, 'n'},
  {"max number of iterations", 1, NULL, 'i'},
  {"minimum threshold", 1, NULL, 't'},
  {"divisor for zero density", 1, NULL, 'q'},
  { 0, 0, 0}
};

float maximum_dif(float *difs, int n){
  int i;
  float max = 0.0f;
  for(i=0; i<n; ++i){
    max = difs[i] > max ? difs[i] : max;
  }
  return max;
}

int main(int argc, char *argv[]) {
  int *pages;
  float *maps;
  float *page_ranks;
  unsigned int *noutlinks;
  int t;
  float max_diff, max_diff_ref;

  int i = 0;
  int j;
  int n = 1000;
  int iter = max_iter;
  float thresh = threshold;
  int divisor = 2;

  int opt, opt_index = 0;
  while((opt = getopt_long(argc, argv, "::n:i:t:q:", size_opts, &opt_index)) != -1){
    switch(opt){
      case 'n':
        n = atoi(optarg);
        break;
      case 'i':
        iter = atoi(optarg);
        break;
      case 't':
        thresh = atof(optarg);
        break;
      case 'q':
        divisor = atoi(optarg);
        break;
      default:
        usage(argv);
        exit(EXIT_FAILURE);
    }
  }

  size_t rank_size = (size_t)n * sizeof(float);
  size_t map_size = (size_t)n * n * sizeof(float);
  size_t page_size = (size_t)n * n * sizeof(int);
  size_t link_size = (size_t)n * sizeof(unsigned int);

  page_ranks = (float*)malloc(rank_size);
  maps = (float*)malloc(map_size);
  noutlinks = (unsigned int*)malloc(link_size);

  max_diff=max_diff_ref=99.0f;

  for (i=0; i<n; ++i) {
    noutlinks[i] = 0;
  }
  pages = random_pages(n,noutlinks,divisor);
  init_array(page_ranks, n, 1.0f / (float) n);

  float *diffs;
  diffs = (float*) malloc(rank_size);

  int *d_pages;
  float *d_maps;
  float *d_page_ranks;
  float *d_diffs;
  unsigned int *d_noutlinks;

  d_pages = (int*)omp_target_alloc(page_size, 0);
  d_page_ranks = (float*)omp_target_alloc(rank_size, 0);
  d_maps = (float*)omp_target_alloc(map_size, 0);
  d_noutlinks = (unsigned int*)omp_target_alloc(link_size, 0);
  d_diffs = (float*)omp_target_alloc(rank_size, 0);

  memset(d_diffs, 0, rank_size);

  omp_target_memcpy(d_pages, pages, page_size, 0, 0, 0, 0);
  omp_target_memcpy(d_page_ranks, page_ranks, rank_size, 0, 0, 0, 0);
  omp_target_memcpy(d_noutlinks, noutlinks, link_size, 0, 0, 0, 0);

  double ktime = 0.0;
  printf("Threshold: %f\n", thresh);

  for (t=1; t<=iter && max_diff>=thresh; ++t) {
    auto start = std::chrono::high_resolution_clock::now();

    map(d_pages, d_page_ranks, d_maps, d_noutlinks, n);
    reduce(d_page_ranks, d_maps, n, d_diffs);

    auto end = std::chrono::high_resolution_clock::now();
    ktime += std::chrono::duration_cast<std::chrono::duration<double>>(end - start).count();

    omp_target_memcpy(diffs, d_diffs, rank_size, 0, 0, 0, 0);
    max_diff = maximum_dif(diffs, n);
  }



  omp_target_free(d_pages, 0);
  omp_target_free(d_maps, 0);
  omp_target_free(d_page_ranks, 0);
  omp_target_free(d_noutlinks, 0);
  omp_target_free(d_diffs, 0);

  fprintf(stderr, "Max difference %f is reached at iteration %d\n", max_diff, t);
  printf("\"Options\": \"-n %d -i %d -t %f\". Total kernel execution time: %lf (s)\n",
         n, iter, thresh, ktime);

  memset(diffs, 0, rank_size);
  for (t=1; t<=iter && max_diff_ref>=thresh; ++t) {
    map_ref(pages, page_ranks, maps, noutlinks, n);
    reduce_ref(page_ranks, maps, n, diffs);
    max_diff_ref = maximum_dif(diffs, n);
  }
  bool ok = fabsf(max_diff - max_diff_ref) < 1e-3f;
  printf("%s\n", ok ? "PASS" : "FAIL");

  free(pages);
  free(maps);
  free(page_ranks);
  free(noutlinks);
  free(diffs);

  return 0;
}
